// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// Iteramos sobre el elemento actual del flujo
for (const item of $input.all()) {

  // 1. Navegamos por el JSON para encontrar el contenido y el nombre
  // OJO: Verifica si n8n le puso un prefijo como "soap:Envelope" a tu JSON tras el parseo.
  const base64String = $input.first().json["soap:Envelope"]["soap:Body"].DescargarDocumentoResponse.DescargarDocumentoResult.ArrayLote;
  const fileName = $input.first().json["soap:Envelope"]["soap:Body"].DescargarDocumentoResponse.DescargarDocumentoResult.NombreArchivo;

  // 2. Le decimos a n8n que cree un objeto binario llamado "miArchivo"
  item.binary = {
    miArchivo: {
      data: base64String,
      fileName: fileName,
      // Le indicamos que es un documento de Word
      mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' 
    }
  };
}

return $input.all();
